import{_ as r,o as t,c as e,a2 as o}from"./chunks/framework.DIMps2S2.js";const _=JSON.parse('{"title":"长期订单影响","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/corporate-actions/impact-on-orders.md","filePath":"zh-CN/stock-trading/corporate-actions/impact-on-orders.md"}'),i={name:"stock-trading/corporate-actions/impact-on-orders.md"};function n(c,a,s,d,l,p){return t(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="长期订单影响" tabindex="-1">长期订单影响 <a class="header-anchor" href="#长期订单影响" aria-label="Permalink to &quot;长期订单影响&quot;">​</a></h1><p>长期订单定义及股份合并分拆对长期订单的影响和取消处理。</p><h2 id="什么是长期订单" tabindex="-1">什么是长期订单 <a class="header-anchor" href="#什么是长期订单" aria-label="Permalink to &quot;什么是长期订单&quot;">​</a></h2><p>长期订单是指除非交易已履行或取消，否则于指定日期前始终有效的订单类型。如交易未获执行，则长期订单会于指定交易日结束后取消。长期订单包括「自定义有效期」及「撤单前有效」订单。</p><h2 id="公司行动会影响长期订单吗" tabindex="-1">公司行动会影响长期订单吗 <a class="header-anchor" href="#公司行动会影响长期订单吗" aria-label="Permalink to &quot;公司行动会影响长期订单吗&quot;">​</a></h2><p>会。当公司行动导致客户持有量发生变化（如股份合并、股份分拆），长期订单将无法继续执行。</p><p>股份合并示例：</p><p>客户持有 A 公司股票 100 股，当前股价 5 元，所持股票价值为 100 * 5 = 500 元。若 A 公司宣布由 10 股合并成 1 股，合并后用户持有 100 / 10 = 10 股，股价将为 5 * 10 = 50 元，所持股票价值仍为 500 元。但客户在股份合并前发出买入 100 股的长期订单，金额为 500 元；合并后同样买入 100 股则需要 5,000 元。由于持股数量及市场价格已有所变化，该长期订单将无法继续执行。</p><p>股份分拆示例：</p><p>客户持有 B 公司股票 100 股，当前股价 5 元，所持股票价值为 100 * 5 = 500 元。若 B 公司宣布由 1 股分拆成 10 股，分拆后用户持有 100 * 10 = 1,000 股，股价将为 5 / 10 = 0.5 元，所持股票价值仍为 500 元。但客户在股份分拆前发出卖出 100 股的长期订单，分拆后同样卖出 100 股仅卖出原股数的 1/10，金额仅为 50 元。由于持股数量及市场价格已有所变化，该长期订单将无法继续执行。</p><h2 id="长桥如何处理受影响的长期订单" tabindex="-1">长桥如何处理受影响的长期订单 <a class="header-anchor" href="#长桥如何处理受影响的长期订单" aria-label="Permalink to &quot;长桥如何处理受影响的长期订单&quot;">​</a></h2><p>有关长期订单将于该公司行动除净日开市前被取消。如有需要，请重新发出交易指示。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/corporate-actions">公司行动</a></li><li><a href="/wiki/stock-trading">股票交易</a></li><li><a href="/wiki/stock-trading/order-types/cancel-order">撤销订单</a></li></ul>',14)])])}const u=r(i,[["render",n]]);export{_ as __pageData,u as default};
